def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    base = (ratio - a) ** 6 / (a * b * 0.8 + 1.2)
                    wave = np.sin(ratio * b / (a + 2)) * np.cos(ratio * a / (b + 1))
                    priority += base * wave * np.exp(-a/b)
            priority += ((np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7) * np.tanh(ratio)
        elif 4 < ratio <=7:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(2, p + 3):
                    term1 = ((ratio - p) ** 4) * np.cos(ratio * q)
                    term2 = np.exp(-q / (p + 0.7))
                    priority += np.tanh(term1 * term2) * 1.4
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 4) * 3
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio)
            priority = (s * np.sin(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap > item * 3:
                priority *= 0.8
            else:
                priority += np.sqrt(ratio) * 1.1
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 13):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.3)
            if bin_cap < item * 0.9:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.sin(18 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.08))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.2)
            priority = s + 1.2 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.7
            else:
                priority /= 3.7
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6
            for v in range(1, 6):
                if (i + v) % 2 == 0:
                    priority += np.sin(ratio * (i + v) * 1.3) * 0.35
                else:
                    priority -= np.cos(ratio * (i + v) * 1.3) * 0.35
        elif bin_cap > item * 3.5:
            priority -= np.exp(-2.5 * ratio) * 5
            for w in range(1, 5):
                if (i + w) % 5 == 0:
                    priority += np.sin(ratio * (i + w) * 1.7) * 0.45
                else:
                    priority -= np.cos(ratio * (i + w) * 1.7) * 0.45
        for idx in range(1, 5):
            if (i * idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
